import React from 'react';

const Menu  = ({showPage}) => {
    const pages = [
        'RegisterPage',
    ];

    return (
        <div className='menu-container'>
            {pages.map(((page, index) => (
                <button key = {index} className='menu-item' 
                onClick = {() => showPage(page)}>{`${page}`}</button>
            )))}
        </div>
    );
}

export default Menu;
